// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-reagenda-cita
const input = $input.first().json;

// Extraer datos
const nueva_fecha_cita = input.nueva_fecha_cita;
const nueva_hora_cita = input.nueva_hora_cita;
const cita_id = input.cita_id;

// VALIDACIONES
const errores = [];

// 1. VALIDAR NUEVA FECHA (YYYY-MM-DD)
const regexFecha = /^\d{4}-\d{2}-\d{2}$/;
if (!nueva_fecha_cita || !regexFecha.test(nueva_fecha_cita)) {
  errores.push(`Fecha inválida: "${nueva_fecha_cita}". Formato requerido: YYYY-MM-DD (ej: 2025-04-30)`);
}

// 2. VALIDAR NUEVA HORA (HH:MM)
const regexHora = /^\d{2}:\d{2}$/;
if (!nueva_hora_cita || !regexHora.test(nueva_hora_cita)) {
  errores.push(`Hora inválida: "${nueva_hora_cita}". Formato requerido: HH:MM (ej: 10:30)`);
}

// Validar que sea uno de los turnos válidos (08:00 a 10:15 cada 15 min)
const turnosValidos = [
  "08:00", "08:15", "08:30", "08:45",
  "09:00", "09:15", "09:30", "09:45",
  "10:00", "10:15"
];
if (nueva_hora_cita && !turnosValidos.includes(nueva_hora_cita)) {
  errores.push(`Hora no permitida: "${nueva_hora_cita}". Solo se aceptan turnos: ${turnosValidos.join(', ')}`);
}

// 3. VALIDAR CITA_ID (debe ser un número entero positivo o string numérico)
if (!cita_id) {
  errores.push(`ID de cita es requerido y no puede estar vacío`);
} else {
  const cita_id_num = parseInt(cita_id);
  if (isNaN(cita_id_num) || cita_id_num <= 0) {
    errores.push(`ID de cita inválido: "${cita_id}". Debe ser un número entero positivo`);
  }
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        nueva_fecha_cita,
        nueva_hora_cita,
        cita_id
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    nueva_fecha_cita,
    nueva_hora_cita,
    cita_id: parseInt(cita_id)
  }
}];

// Procesar respuesta de creación de cita
const response = $input.first().json;

// Verificar si la creación fue exitosa
const exitoso = response.ResponseResult === 0;

if (exitoso) {
  // Cita creada exitosamente
  return {
    json: {
      exitoso: true,
      mensaje: "Cita reagendada exitosamente",      
      fechaCita: $('validar-formato').first().json.nueva_fecha_cita,
      horaCita: $('validar-formato').first().json.nueva_hora_cita,      
    }
  };
} else {
  // Hubo un error en la creación
  return {
    json: {
      exitoso: false,
      mensaje: "Error al reagendar la cita",
      codigoError: response.ResponseResult,
      tipoError: response.ExceptionType || "Desconocido",
      detalleError: response.ExceptionMessage || "Sin detalles",
      informacionAdicional: response.ExceptionInfo || null
    }
  };
}

// Procesar salida con error de validación
const errorData = $input.first().json;

return [{
  json: {
    exitoso: false,
    tipoError: errorData.error || "ERROR_DESCONOCIDO",
    mensaje: "No se pudo reagendar la cita debido a errores de validación",
    errores: errorData.errores || [],
    cantidadErrores: (errorData.errores || []).length,
    datosRecibidos: {
      fechaCita: errorData.datos_recibidos?.fecha_cita || null,
      horaCita: errorData.datos_recibidos?.hora_cita || null,
      nombreCliente: errorData.datos_recibidos?.nombre_cliente || null,
      apellidoCliente: errorData.datos_recibidos?.apellido_cliente || null,
      modeloVehiculo: errorData.datos_recibidos?.modelo_vehiculo || null,
      patenteVehiculo: errorData.datos_recibidos?.patente_vehiculo || null,
      tallerSolicitado: errorData.datos_recibidos?.taller_solicitado || null,
      servicioSolicitado: errorData.datos_recibidos?.servicio_solicitado || null
    },
    timestamp: new Date().toISOString()
  }
}];

let data = $('get-one-cita-by-id').first().json.InternalObject;

// ⭐ FECHA_HORA - COMBINAR FECHA + HORA en formato ISO 8601
let fechayhora_var = data.CustomFields.find(item => item.Name === 'FECHA_HORA');
const fecha = $('validar-formato').first().json.nueva_fecha_cita;  // "2025-11-28"
const hora = $('validar-formato').first().json.nueva_hora_cita;    // "08:00"
// Combinar en formato ISO: "2025-11-28T08:00:00"
fechayhora_var.Value = `${fecha}T${hora}:00-03:00`;
//fechayhora_var.Value = `2025-11-27T19:30:00Z`;
//2025-11-27T19:30:00Z
// MODELO
// let modelo_var = data.CustomFields.find(item => item.Name === 'MODELO');
// modelo_var.Value = $('validar-formato').first().json.modelo_vehiculo;


return [
  {
      JSON: {
          document: data        
      }
  }
]
